// Use IST timezone (UTC+5:30) for all time calculations
const now = new Date();
const istOffset = 5.5 * 60 * 60 * 1000;
const istNow = new Date(now.getTime() + istOffset);

const today = istNow.toISOString().split('T')[0];
const hour = istNow.getUTCHours();  // hours in IST

const rows = $input.all();
const todayTotal = rows
  .filter(r => r.json.date === today)
  .reduce((sum, r) => sum + (parseFloat(r.json.ml) || 0), 0);

const target = 3000;
const remaining = target - todayTotal;
const hoursLeft = 22 - hour;

// Expected ml by this hour (linear: 8am-10pm IST = 14 hours)
const hoursPassed = Math.max(0, hour - 8);
const expectedByNow = Math.round((hoursPassed / 14) * target);

if (todayTotal >= expectedByNow) {
  return [];  // On track — stop here, no alert needed
}

let msg = `💧 <b>Water Reminder</b>\n\nYou've had ${todayTotal}ml / ${target}ml today.\n${remaining}ml more in ${hoursLeft} hours.\n\n`;
if (todayTotal === 0) msg += 'Time to start hydrating! 🥤';
else if (todayTotal < 500) msg += "You're behind - try to catch up!";
else msg += `Almost there! Just ${remaining}ml more.`;

return [{ json: { message: msg, total: todayTotal, target, hour, expectedByNow } }];
